// Pobierz przetworzone URL z poprzednich runów
const staticData = $getWorkflowStaticData('global');
const seen = new Set(staticData.seenUrls || []);

const cutoff = Date.now() - 24 * 60 * 60 * 1000; // 24h
const fresh = [];
const newSeen = [];

for (const item of $input.all()) {
  const pub = item.json.pubDate || item.json.isoDate || item.json.date || '';
  const url = item.json.link || item.json.url || '';
  const title = item.json.title || '';

  if (!url || !title) continue;
  if (seen.has(url)) continue;

  // Sprawdź czy artykuł jest z ostatnich 24h
  const pubTime = pub ? new Date(pub).getTime() : Date.now();
  if (pub && pubTime < cutoff) continue;

  fresh.push({ json: {
    title,
    url,
    description: (item.json.contentSnippet || item.json.summary || item.json.content || '').slice(0, 400),
    source: item.json.feedTitle || new URL(url).hostname,
    published: pub,
  }});
  newSeen.push(url);
}

// Ogranicz do 60 artykułów na run
const result = fresh.slice(0, 60);

// Zapisz nowe URL do static data (max 1000 wpisów)
staticData.seenUrls = [...seen, ...newSeen].slice(-1000);

if (result.length === 0) {
  return [{ json: { isEmpty: true, count: 0 } }];
}

return [{ json: { isEmpty: false, count: result.length, articles: result.map(r => r.json) } }];

