const body = $input.first().json;
const text = body?.content?.[0]?.text || '[]';

let models = [];
try {
  // Wyciągnij JSON z odpowiedzi (może mieć markdown)
  const match = text.match(/\[.*\]/s);
  if (match) models = JSON.parse(match[0]);
} catch(e) {
  console.log('Parse error:', e.message, 'text:', text.slice(0,200));
}

if (!Array.isArray(models) || models.length === 0) {
  return [{ json: { isEmpty: true, models: [] } }];
}

// Filtruj niepełne wpisy
models = models.filter(m => m.name && m.provider && m.url);

return [{ json: { isEmpty: models.length === 0, count: models.length, models } }];

